/* Generated by scripts/generate-service-worker.mjs. */
const BUILD_ID = 'a3ccf5089e16';
const CACHE_PREFIX = 'balthasar-pwa-';
const SHELL_CACHE = CACHE_PREFIX + 'shell-' + BUILD_ID;
const STATIC_CACHE = CACHE_PREFIX + 'static-' + BUILD_ID;
const SHELL_ASSETS = [
  "/offline.html",
  "/manifest.webmanifest",
  "/pwa/icon-192.png",
  "/pwa/icon-512.png",
  "/pwa/icon-maskable-512.png"
];

async function clients() {
  try { return await self.clients.matchAll({ includeUncontrolled: true }); }
  catch { return []; }
}

async function announceReady() {
  const list = await clients();
  for (const client of list) {
    try {
      client.postMessage({ type: 'WORKER_READY', buildId: BUILD_ID });
    } catch {
      // Client may have gone away; safe to ignore.
    }
  }
}

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(SHELL_CACHE)
      .then((cache) => cache.addAll(SHELL_ASSETS))
      .then(() => announceReady())
      .catch((error) => {
        // Cache failure is reportable; the page can warn the user that the
        // offline shell will not be available after this load.
        const list = self.clients && self.clients.matchAll
          ? self.clients.matchAll({ includeUncontrolled: true })
          : Promise.resolve([]);
        return list.then((clients) => {
          for (const client of clients) {
            try {
              client.postMessage({
                type: 'CACHE_ERROR',
                buildId: BUILD_ID,
                resourceKind: 'shell',
              });
            } catch {
              // Swallow — never throw out of install handler.
            }
          }
          throw error;
        });
      })
  );
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((keys) => Promise.all(keys.map((key) =>
      key.startsWith(CACHE_PREFIX) && key !== SHELL_CACHE && key !== STATIC_CACHE
        ? caches.delete(key)
        : undefined
    ))).then(() => self.clients.claim()).then(() => announceReady())
  );
});

self.addEventListener('fetch', (event) => {
  const request = event.request;
  const url = new URL(request.url);
  if (request.method !== 'GET') return;
  if (
    url.origin !== self.location.origin ||
    url.pathname.startsWith('/api/') ||
    url.pathname.startsWith('/api/auth') ||
    url.pathname.startsWith('/api/trpc') ||
    request.headers.has('RSC') ||
    request.headers.has('Next-Router-State-Tree')
  ) return;

  if (request.mode === 'navigate') {
    event.respondWith(fetch(request).catch(() => {
      return caches.match('/offline.html');
    }));
    return;
  }

  if (SHELL_ASSETS.includes(url.pathname)) {
    event.respondWith(caches.match(request).then((cached) => cached || fetch(request)));
    return;
  }

  if (url.pathname.startsWith('/_next/static/')) {
    event.respondWith(caches.match(request).then(async (cached) => {
      if (cached) return cached;
      const response = await fetch(request);
      if (response.ok && response.status === 200) {
        const cache = await caches.open(STATIC_CACHE);
        try {
          await cache.put(request, response.clone());
        } catch (error) {
          const list = self.clients && self.clients.matchAll
            ? self.clients.matchAll({ includeUncontrolled: true })
            : Promise.resolve([]);
          list.then((clients) => {
            for (const client of clients) {
              try {
                client.postMessage({
                  type: 'CACHE_ERROR',
                  buildId: BUILD_ID,
                  resourceKind: 'static',
                });
              } catch {
                // Swallow — fetch still returns the response.
              }
            }
          });
        }
      }
      return response;
    }));
  }
});

self.addEventListener('message', (event) => {
  // Only activate the new worker when the page explicitly opts in AND the
  // buildId matches — prevents stale tabs from forcing an update that drops
  // an unsaved draft.
  if (
    event.data &&
    event.data.type === 'SKIP_WAITING' &&
    event.data.buildId === BUILD_ID
  ) {
    self.skipWaiting();
  }
});

// ── 033 US2 / R4:断网记账队列后台同步 ──
// SW 用原生 indexedDB(不引 idb 库,保持 SW 依赖最小)。schema 与
// src/lib/offline/db.ts 一致:DB balthasar-offline,store pending_queue
// (keyPath clientRequestId)。flush 读 pending → POST /api/v1/transactions/sync
// (session cookie 自动带,credentials:include)→ 按 HTTP status 更新/出队。
const OFFLINE_DB_NAME = 'balthasar-offline';
const OFFLINE_DB_VERSION = 1;
const SYNC_ENDPOINT = '/api/v1/transactions/sync';
const MAX_RETRY = 5;

function openOfflineDBInSW() {
  return new Promise((resolve, reject) => {
    const req = indexedDB.open(OFFLINE_DB_NAME, OFFLINE_DB_VERSION);
    req.onupgradeneeded = () => {
      const db = req.result;
      if (!db.objectStoreNames.contains('pending_queue')) {
        db.createObjectStore('pending_queue', { keyPath: 'clientRequestId' });
      }
      // 其它 store(tansactions/dashboard_summaries/meta)由 page 端建;
      // SW 只用 pending_queue,但 open 同 version 不冲突。
    };
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });
}

function txAllPending(db) {
  return new Promise((resolve, reject) => {
    const tx = db.transaction('pending_queue', 'readonly');
    const store = tx.objectStore('pending_queue');
    const req = store.getAll();
    req.onsuccess = () => resolve(req.result || []);
    req.onerror = () => reject(req.error);
  });
}

function txPut(db, item) {
  return new Promise((resolve, reject) => {
    const tx = db.transaction('pending_queue', 'readwrite');
    tx.objectStore('pending_queue').put(item);
    tx.oncomplete = () => resolve();
    tx.onerror = () => reject(tx.error);
  });
}

function txDelete(db, id) {
  return new Promise((resolve, reject) => {
    const tx = db.transaction('pending_queue', 'readwrite');
    tx.objectStore('pending_queue').delete(id);
    tx.oncomplete = () => resolve();
    tx.onerror = () => reject(tx.error);
  });
}

// 把 HTTP 响应映射到 NextAction(与 src/lib/offline/queue-state.ts 同语义)
function statusToAction(status, item) {
  // 2xx → delete(成功 / dedup 命中也走此路,procedure 返既有)
  if (status >= 200 && status < 300) return { kind: 'delete' };
  // 401 → failed(认证失效,不重试)
  if (status === 401) return { kind: 'update', item: { ...item, status: 'failed', lastError: 'auth' } };
  // 4xx 永久 → delete(drop 坏数据)
  if (status >= 400 && status < 500) return { kind: 'delete' };
  // 5xx / network 瞬时 → retry++ 或达上限 failed
  if (item.retryCount >= MAX_RETRY) {
    return { kind: 'update', item: { ...item, status: 'failed', retryCount: item.retryCount, lastError: String(status) } };
  }
  const nextRetry = item.retryCount + 1;
  if (nextRetry >= MAX_RETRY) {
    return { kind: 'update', item: { ...item, status: 'failed', retryCount: nextRetry, lastError: String(status) } };
  }
  return { kind: 'update', item: { ...item, status: 'pending', retryCount: nextRetry, lastError: String(status) } };
}

async function flushPendingQueue() {
  const db = await openOfflineDBInSW();
  const items = await txAllPending(db);
  // 仅 pending/syncing,按 createdAt 升序逐条(契约 FR-006 顺序)
  const active = items
    .filter((i) => i && i.status !== 'failed')
    .sort((a, b) => (a.createdAt || 0) - (b.createdAt || 0));
  for (const item of active) {
    let status;
    try {
      const res = await fetch(SYNC_ENDPOINT, {
        method: 'POST',
        credentials: 'include',
        headers: {
          'Content-Type': 'application/json',
          'X-Client-Request-Id': item.clientRequestId,
        },
        body: JSON.stringify(item.formPayload || {}),
      });
      status = res.status;
    } catch (e) {
      // network error → 视同 5xx(retry)
      status = 500;
    }
    const action = statusToAction(status, item);
    if (action.kind === 'delete') {
      await txDelete(db, item.clientRequestId);
    } else {
      await txPut(db, action.item);
    }
  }
}

// Background Sync(Android Chrome / 桌面 Chrome/Edge)
self.addEventListener('sync', (event) => {
  if (event.tag === 'balthasar-flush-queue') {
    event.waitUntil(flushPendingQueue());
  }
});

// 前台降级(iOS Safari / 不支持 sync):page postMessage 触发立即 flush
self.addEventListener('message', (event) => {
  if (event.data && event.data.type === 'FLUSH_PENDING_QUEUE') {
    event.waitUntil(flushPendingQueue());
  }
});

